import React, { useState, useEffect } from 'react';
import { MapPin, Loader2 } from 'lucide-react'; // Eliminamos Search que no se usaba
import { calcularDistanciaReal } from '../utils/shippingService';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

// Coordenadas fijas del local
const COORDS_LOCAL = { lat: -26.732479, lon: -65.267028 }; 

const PanelCliente = () => {
  const [ofertas, setOfertas] = useState([]);
  const [cart, setCart] = useState([]);
  const [pedidos, setPedidos] = useState([]);
  
  // Estados para Ubicación
  const [busqueda, setBusqueda] = useState("");
  const [sugerencias, setSugerencias] = useState([]);
  const [cargandoUbicacion, setCargandoUbicacion] = useState(false);
  const [distanciaReal, setDistanciaReal] = useState(0);
  const [direccionSeleccionada, setDireccionSeleccionada] = useState(null);

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acc = [];
    locales.forEach(l => {
      const ofs = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      acc = [...acc, ...ofs.map(o => ({ ...o, nombreLocal: l.nombre, localId: l.id }))];
    });
    setOfertas(acc);
  }, []);

  const buscarDireccion = async (texto) => {
    setBusqueda(texto);
    if (texto.length < 4) {
      setSugerencias([]);
      return;
    }

    setCargandoUbicacion(true);
    try {
      const response = await fetch(
        `https://nominatim.openstreetmap.org/search?format=json&q=${texto}&countrycodes=ar&addressdetails=1&limit=5`
      );
      const data = await response.json();
      setSugerencias(data);
    } catch (error) {
      console.error("Error en geocodificación:", error);
    } finally {
      setCargandoUbicacion(false);
    }
  };

  const seleccionarDireccion = (item) => {
    const latCli = parseFloat(item.lat);
    const lonCli = parseFloat(item.lon);
    
    // AQUÍ SE USA calcularDistanciaReal y COORDS_LOCAL
    const d = calcularDistanciaReal(latCli, lonCli, COORDS_LOCAL.lat, COORDS_LOCAL.lon);
    
    setDistanciaReal(d);
    
    const ciudad = item.address.city || item.address.town || item.address.village || "Tucumán";
    const provincia = item.address.state || "Tucumán";
    const nombreLargo = `${item.address.road || ''} ${item.address.house_number || ''}, ${ciudad}, ${provincia}`;
    
    setDireccionSeleccionada(nombreLargo);
    setBusqueda(nombreLargo);
    setSugerencias([]);
  };

  const handlePagoExitoso = (totalPagado) => {
    const nuevoPedido = { 
      id: `PED-${Date.now()}`, 
      total: totalPagado, 
      distancia: distanciaReal,
      direccion: direccionSeleccionada 
    };
    setPedidos([nuevoPedido, ...pedidos]);
    setCart([]);
  };

  return (
    <div style={layoutContainer}>
      <div style={{ flex: 1 }}>
        
        {/* BUSCADOR CON AUTOCOMPLETADO */}
        <div style={{ position: 'relative', marginBottom: '30px' }}>
          <div style={addressPicker}>
            <MapPin size={20} color="#e67e22" />
            <input 
              type="text" 
              placeholder="Escribe calle y altura..." 
              style={inputAddress}
              value={busqueda}
              onChange={(e) => buscarDireccion(e.target.value)}
            />
            {cargandoUbicacion && <Loader2 size={18} className="animate-spin" style={{marginLeft: '10px'}} />}
          </div>

          {sugerencias.length > 0 && (
            <div style={dropdownSugerencias}>
              {sugerencias.map((item, index) => (
                <div 
                  key={index} 
                  style={itemSugerencia} 
                  onClick={() => seleccionarDireccion(item)}
                >
                  <div style={{fontWeight: 'bold'}}>
                    {item.address.road} {item.address.house_number}
                  </div>
                  <div style={{ fontSize: '0.75rem', color: '#64748b' }}>
                    {item.address.city || item.address.town || ''}, {item.address.state}
                  </div>
                </div>
              ))}
            </div>
          )}
          
          {direccionSeleccionada && (
            <div style={distanciaTag}>
              Distancia al local: <strong>{distanciaReal} km</strong>
            </div>
          )}
        </div>

        <h2 style={{color: '#1e293b', marginBottom: '20px'}}>Ofertas Disponibles</h2>
        <div style={gridStyle}>
          {ofertas.map(o => (
            <div key={o.id} style={cardStyle}>
              {o.imagen && <img src={o.imagen} style={imgStyle} alt="" />}
              <div style={{padding: '15px'}}>
                <small style={{color: '#e67e22', fontWeight: 'bold'}}>{o.nombreLocal}</small>
                <h4 style={{margin: '5px 0', fontSize: '1rem'}}>{o.producto}</h4>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '10px'}}>
                  <span style={{fontWeight: 'bold', fontSize: '1.1rem'}}>${o.precioNuevo}</span>
                  <button onClick={() => setCart([...cart, o])} style={btnAddToCart}>Agregar</button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div style={{ width: '380px' }}>
        <Carrito 
          cart={cart} 
          setCart={setCart} 
          distanciaReal={distanciaReal} 
          onCheckout={handlePagoExitoso} 
        />
        {pedidos.map(p => (
          <div key={p.id} style={{marginTop: '20px'}}>
             <SeguimientoPedido pedido={p} />
          </div>
        ))}
      </div>
    </div>
  );
};

// --- ESTILOS ---
const layoutContainer = { display: 'flex', gap: '30px', padding: '20px 5%', background: '#f8fafc', minHeight: '100vh' };
const addressPicker = { display: 'flex', alignItems: 'center', background: 'white', padding: '12px 20px', borderRadius: '15px', boxShadow: '0 4px 12px rgba(0,0,0,0.08)', gap: '10px', border: '1px solid #e2e8f0' };
const inputAddress = { flex: 1, border: 'none', outline: 'none', fontSize: '1rem', color: '#1e293b' };
const dropdownSugerencias = { position: 'absolute', top: '110%', left: 0, right: 0, background: 'white', borderRadius: '12px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)', zIndex: 100, border: '1px solid #f1f5f9', overflow: 'hidden' };
const itemSugerencia = { padding: '12px 20px', cursor: 'pointer', borderBottom: '1px solid #f1f5f9' };
const distanciaTag = { marginTop: '10px', fontSize: '0.85rem', color: '#166534', background: '#f0fdf4', display: 'inline-block', padding: '4px 12px', borderRadius: '20px' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '20px' };
const cardStyle = { background: 'white', borderRadius: '15px', overflow: 'hidden', border: '1px solid #e2e8f0' };
const imgStyle = { width: '100%', height: '140px', objectFit: 'cover' };
const btnAddToCart = { background: '#1e293b', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '10px', cursor: 'pointer', fontWeight: '600' };

export default PanelCliente;
